+        transport,
+      );
+      const rendered = customAdapter.renderTemplate(makePayload({
+        type: 'user-welcome',
+      }));
+
+      expect(rendered.htmlBody).toContain('Welcome to MyApp');
+    });
+  });
+
+  describe('configuration', () => {
+    it('should use default config when none provided', async () => {
+      await adapter.send(makePayload());
+
+      const sent = transport.getSentEmails();
+      // Default from address is used by the transport
+      expect(sent).toHaveLength(1);
+    });
+
+    it('should use custom from address', async () => {
+      const customTransport: EmailTransport = {
+        lastFrom: '',
+        async sendMail(options) {
+          (this as any).lastFrom = options.from;
+          return { messageId: 'test-1' };
+        },
+      } as any;
+
+      const customAdapter = new EmailAdapter(
+        { fromAddress: 'custom@myapp.com' },
+        customTransport,
+      );
+      await customAdapter.send(makePayload());
+
+      expect((customTransport as any).lastFrom).toBe('custom@myapp.com');
+    });
+  });
+
+  describe('getSentEmails / clearSentEmails', () => {
+    it('should return empty array initially', () => {
+      expect(adapter.getSentEmails()).toEqual([]);
+    });
+
+    it('should clear sent emails', async () => {
+      await adapter.send(makePayload());
+      expect(adapter.getSentEmails()).toHaveLength(1);
+
+      adapter.clearSentEmails();
+      expect(adapter.getSentEmails()).toEqual([]);
+    });
+
+    it('should return empty array when using non-InMemory transport', () => {
+      const customAdapter = new EmailAdapter(undefined, {
+        async sendMail() {
+          return { messageId: '1' };
+        },
+      });
+      expect(customAdapter.getSentEmails()).toEqual([]);
+    });
+  });
+
+  describe('channel property', () => {
+    it('should be email', () => {
+      expect(adapter.channel).toBe('email');
+    });
+  });
+});
+
+describe('InMemoryTransport', () => {
+  let transport: InMemoryTransport;
+
+  beforeEach(() => {
+    transport = new InMemoryTransport();
+  });
+
+  it('should record sent emails', async () => {
+    await transport.sendMail({
+      from: 'from@test.com',
+      to: 'to@test.com',
+      subject: 'Test',
+      text: 'Hello',
+      html: '<p>Hello</p>',
+    });
+
+    const sent = transport.getSentEmails();
+    expect(sent).toHaveLength(1);
