/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the 'email' channel with:
 * - Template rendering based on notification type
 * - Recipient email validation
 * - Configurable email transport (injectable for testing)
 * - Retry-friendly error handling (never throws, returns success/failure)
 */

import type { NotificationAdapter, AdapterSendResult } from './notification.adapter.js';
import type { NotificationPayload } from '../models/notification.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * A recorded email for inspection in tests and debugging.
 */
export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  htmlBody: string;
  sentAt: Date;
}

/**
 * Configuration for the email adapter.
 */
export interface EmailAdapterConfig {
  /** Sender email address shown in the "From" field */
  fromAddress: string;
  /** Application name used in templates */
  appName: string;
}

/**
 * Transport interface for actually sending emails.
 * Inject a real implementation (SMTP, SES, SendGrid) in production,
 * or use the default in-memory transport for testing.
 */
export interface EmailTransport {
  sendMail(options: {
    from: string;
    to: string;
    subject: string;
    text: string;
    html: string;
  }): Promise<{ messageId: string }>;
}

/**
 * Default in-memory transport that records emails instead of sending them.
 * Used in development and testing.
 */
export class InMemoryTransport implements EmailTransport {
  private sent: SentEmail[] = [];
  private nextId = 1;

  async sendMail(options: {
    from: string;
    to: string;
    subject: string;
    text: string;
    html: string;
  }): Promise<{ messageId: string }> {
    this.sent.push({
      to: options.to,
      subject: options.subject,
      body: options.text,
      htmlBody: options.html,
      sentAt: new Date(),
    });
    return { messageId: `msg-${String(this.nextId++).padStart(4, '0')}` };
  }

  getSentEmails(): SentEmail[] {
    return [...this.sent];
  }

  clear(): void {
    this.sent = [];
    this.nextId = 1;
  }
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Template definitions keyed by notification type.
 * Each returns { subject, textBody, htmlBody } given the payload.
 */
type TemplateRenderer = (payload: NotificationPayload, config: EmailAdapterConfig) => {
  subject: string;
  textBody: string;
  htmlBody: string;
};

const templates: Record<NotificationType, TemplateRenderer> = {
  'order-confirmation': (payload, config) => ({
    subject: payload.subject,
    textBody: payload.body,
    htmlBody: `<div style="font-family:sans-serif;max-width:600px;margin:0 auto">` +
      `<h2 style="color:#2563eb">${config.appName}</h2>` +
      `<h3>Order Confirmation</h3>` +
      `<p>${escapeHtml(payload.body)}</p>` +
      `<p style="color:#6b7280;font-size:12px">Thank you for your order!</p>` +
      `</div>`,
  }),

  'order-status-update': (payload, config) => ({
    subject: payload.subject,
    textBody: payload.body,
    htmlBody: `<div style="font-family:sans-serif;max-width:600px;margin:0 auto">` +
      `<h2 style="color:#2563eb">${config.appName}</h2>` +
      `<h3>Order Status Update</h3>` +
      `<p>${escapeHtml(payload.body)}</p>` +
      `<p style="color:#6b7280;font-size:12px">Track your order anytime in your account.</p>` +
      `</div>`,
  }),

  'user-welcome': (payload, config) => ({
    subject: payload.subject,
    textBody: payload.body,
    htmlBody: `<div style="font-family:sans-serif;max-width:600px;margin:0 auto">` +
      `<h2 style="color:#2563eb">Welcome to ${config.appName}!</h2>` +
      `<p>${escapeHtml(payload.body)}</p>` +
      `<p style="color:#6b7280;font-size:12px">We're glad to have you on board.</p>` +
      `</div>`,
  }),

  'user-profile-update': (payload, config) => ({
    subject: payload.subject,
    textBody: payload.body,
    htmlBody: `<div style="font-family:sans-serif;max-width:600px;margin:0 auto">` +
      `<h2 style="color:#2563eb">${config.appName}</h2>` +
      `<h3>Profile Updated</h3>` +
      `<p>${escapeHtml(payload.body)}</p>` +
      `</div>`,
  }),

  'system-alert': (payload, config) => ({
    subject: `[${config.appName}] ${payload.subject}`,
    textBody: payload.body,
    htmlBody: `<div style="font-family:sans-serif;max-width:600px;margin:0 auto">` +
      `<h2 style="color:#dc2626">${config.appName} — System Alert</h2>` +
      `<p style="font-weight:bold">${escapeHtml(payload.body)}</p>` +
      `</div>`,
  }),
};

function escapeHtml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

const defaultConfig: EmailAdapterConfig = {
  fromAddress: 'noreply@taskflowpro.com',
  appName: 'TaskFlow Pro',
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private config: EmailAdapterConfig;
  private transport: EmailTransport;

  constructor(config?: Partial<EmailAdapterConfig>, transport?: EmailTransport) {
    this.config = { ...defaultConfig, ...config };
    this.transport = transport ?? new InMemoryTransport();
  }

  async send(payload: NotificationPayload): Promise<AdapterSendResult> {
    // Validate recipient email
    if (!this.isValidEmail(payload.recipient)) {
      this.logger.warn(`Invalid email address: ${payload.recipient}`);
      return {
        success: false,
        error: `Invalid email address: ${payload.recipient}`,
      };
    }

    // Render template
    const rendered = this.renderTemplate(payload);

    // Send via transport
    try {
      const result = await this.transport.sendMail({
        from: this.config.fromAddress,
        to: payload.recipient,
        subject: rendered.subject,
        text: rendered.textBody,
        html: rendered.htmlBody,
      });

      this.logger.info(`Email sent to ${payload.recipient}: ${rendered.subject} (${result.messageId})`);

      return {
        success: true,
        providerResponse: { messageId: result.messageId },
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`Failed to send email to ${payload.recipient}: ${message}`);
      return {
        success: false,
        error: message,
      };
    }
  }

  /**
   * Render the notification payload through the type-specific template.
   */
  renderTemplate(payload: NotificationPayload): {
    subject: string;
    textBody: string;
    htmlBody: string;
  } {
    const renderer = templates[payload.type];
    return renderer(payload, this.config);
  }

  /**
   * Validate an email address format.
   */
  isValidEmail(email: string): boolean {
    return EMAIL_REGEX.test(email);
  }

  /**
   * Get all emails sent through this adapter (only works with InMemoryTransport).
   */
  getSentEmails(): SentEmail[] {
    if (this.transport instanceof InMemoryTransport) {
      return this.transport.getSentEmails();
    }
    return [];
  }

  /**
   * Clear recorded emails (only works with InMemoryTransport).
   */
  clearSentEmails(): void {
    if (this.transport instanceof InMemoryTransport) {
      this.transport.clear();
    }
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailAdapter,
  InMemoryTransport,
} from '../../src/adapters/email.adapter.js';
import type { EmailTransport } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: 'alice@example.com',
    subject: 'Test Subject',
    body: 'Test body content',
    channel: 'email',
    type: 'order-confirmation',
    priority: 'normal',
    ...overrides,
  };
}

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
    adapter = new EmailAdapter(undefined, transport);
  });

  describe('send', () => {
    it('should send an email successfully', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.providerResponse?.messageId).toBe('msg-0001');
    });

    it('should record emails via InMemoryTransport', async () => {
      await adapter.send(makePayload());

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.subject).toBe('Test Subject');
    });

    it('should reject invalid email addresses', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
    });

    it('should reject empty email addresses', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
    });

    it('should handle transport errors without throwing', async () => {
      const failingTransport: EmailTransport = {
        async sendMail() {
          throw new Error('SMTP connection refused');
        },
      };
      const failAdapter = new EmailAdapter(undefined, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
    });

    it('should handle non-Error transport exceptions', async () => {
      const failingTransport: EmailTransport = {
        async sendMail() {
          throw 'string error';
        },
      };
      const failAdapter = new EmailAdapter(undefined, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Unknown transport error');
    });

    it('should return sequential message IDs', async () => {
      const r1 = await adapter.send(makePayload());
      const r2 = await adapter.send(makePayload({ recipient: 'bob@example.com' }));

      expect(r1.providerResponse?.messageId).toBe('msg-0001');
      expect(r2.providerResponse?.messageId).toBe('msg-0002');
    });
  });

  describe('email validation', () => {
    it.each([
      'user@example.com',
      'user.name@example.co.uk',
      'user+tag@domain.org',
    ])('should accept valid email: %s', (email) => {
      expect(adapter.isValidEmail(email)).toBe(true);
    });

    it.each([
      '',
      'noatsign',
      '@nodomain',
      'user@',
      'user @space.com',
    ])('should reject invalid email: "%s"', (email) => {
      expect(adapter.isValidEmail(email)).toBe(false);
    });
  });

  describe('template rendering', () => {
    it('should render order-confirmation template with HTML', () => {
      const rendered = adapter.renderTemplate(makePayload({
        type: 'order-confirmation',
        body: 'Items: Widget x2. Total: $20.00',
      }));

      expect(rendered.subject).toBe('Test Subject');
      expect(rendered.textBody).toContain('Widget x2');
      expect(rendered.htmlBody).toContain('Order Confirmation');
      expect(rendered.htmlBody).toContain('Widget x2');
      expect(rendered.htmlBody).toContain('TaskFlow Pro');
    });

    it('should render order-status-update template', () => {
      const rendered = adapter.renderTemplate(makePayload({
        type: 'order-status-update',
        body: 'Status changed from pending to confirmed.',
      }));

      expect(rendered.htmlBody).toContain('Order Status Update');
      expect(rendered.htmlBody).toContain('pending');
    });

    it('should render user-welcome template', () => {
      const rendered = adapter.renderTemplate(makePayload({
        type: 'user-welcome',
        body: 'Welcome, Alice!',
      }));

      expect(rendered.htmlBody).toContain('Welcome to TaskFlow Pro');
      expect(rendered.htmlBody).toContain('Welcome, Alice!');
    });

    it('should render user-profile-update template', () => {
      const rendered = adapter.renderTemplate(makePayload({
        type: 'user-profile-update',
        body: 'Your profile has been updated.',
      }));

      expect(rendered.htmlBody).toContain('Profile Updated');
    });

    it('should render system-alert template with prefixed subject', () => {
      const rendered = adapter.renderTemplate(makePayload({
        type: 'system-alert',
        subject: 'High CPU Usage',
      }));

      expect(rendered.subject).toBe('[TaskFlow Pro] High CPU Usage');
      expect(rendered.htmlBody).toContain('System Alert');
    });

    it('should escape HTML in body content', () => {
      const rendered = adapter.renderTemplate(makePayload({
        body: '<script>alert("xss")</script>',
      }));

      expect(rendered.htmlBody).not.toContain('<script>');
      expect(rendered.htmlBody).toContain('&lt;script&gt;');
    });

    it('should use custom app name from config', () => {
      const customAdapter = new EmailAdapter(
        { appName: 'MyApp' },
        transport,
      );
      const rendered = customAdapter.renderTemplate(makePayload({
        type: 'user-welcome',
      }));

      expect(rendered.htmlBody).toContain('Welcome to MyApp');
    });
  });

  describe('configuration', () => {
    it('should use default config when none provided', async () => {
      await adapter.send(makePayload());

      const sent = transport.getSentEmails();
      // Default from address is used by the transport
      expect(sent).toHaveLength(1);
    });

    it('should use custom from address', async () => {
      const customTransport: EmailTransport = {
        lastFrom: '',
        async sendMail(options) {
          (this as any).lastFrom = options.from;
          return { messageId: 'test-1' };
        },
      } as any;

      const customAdapter = new EmailAdapter(
        { fromAddress: 'custom@myapp.com' },
        customTransport,
      );
      await customAdapter.send(makePayload());

      expect((customTransport as any).lastFrom).toBe('custom@myapp.com');
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should return empty array initially', () => {
      expect(adapter.getSentEmails()).toEqual([]);
    });

    it('should clear sent emails', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toEqual([]);
    });

    it('should return empty array when using non-InMemory transport', () => {
      const customAdapter = new EmailAdapter(undefined, {
        async sendMail() {
          return { messageId: '1' };
        },
      });
      expect(customAdapter.getSentEmails()).toEqual([]);
    });
  });

  describe('channel property', () => {
    it('should be email', () => {
      expect(adapter.channel).toBe('email');
    });
  });
});

describe('InMemoryTransport', () => {
  let transport: InMemoryTransport;

  beforeEach(() => {
    transport = new InMemoryTransport();
  });

  it('should record sent emails', async () => {
    await transport.sendMail({
      from: 'from@test.com',
      to: 'to@test.com',
      subject: 'Test',
      text: 'Hello',
      html: '<p>Hello</p>',
    });

    const sent = transport.getSentEmails();
    expect(sent).toHaveLength(1);
    expect(sent[0]?.to).toBe('to@test.com');
    expect(sent[0]?.body).toBe('Hello');
    expect(sent[0]?.htmlBody).toBe('<p>Hello</p>');
  });

  it('should clear all emails', async () => {
    await transport.sendMail({
      from: 'a@b.com',
      to: 'c@d.com',
      subject: 's',
      text: 't',
      html: 'h',
    });
    transport.clear();
    expect(transport.getSentEmails()).toEqual([]);
  });

  it('should generate sequential message IDs', async () => {
    const r1 = await transport.sendMail({
      from: 'a@b.com', to: 'c@d.com', subject: '', text: '', html: '',
    });
    const r2 = await transport.sendMail({
      from: 'a@b.com', to: 'c@d.com', subject: '', text: '', html: '',
    });

    expect(r1.messageId).toBe('msg-0001');
    expect(r2.messageId).toBe('msg-0002');
  });

  it('should reset IDs on clear', async () => {
    await transport.sendMail({
      from: 'a@b.com', to: 'c@d.com', subject: '', text: '', html: '',
    });
    transport.clear();
    const r = await transport.sendMail({
      from: 'a@b.com', to: 'c@d.com', subject: '', text: '', html: '',
    });
    expect(r.messageId).toBe('msg-0001');
  });
});
